import logo from '../images/krypton.svg'

function Navbar() {
    return (
        <nav>
            <div className="logo-countainer">
                <img src={logo} className='logo' />
                <p className='logo-title'>Krypton</p>
            </div>
        </nav>
    )
}

export default Navbar
